/**
 * @summary Upload a file
 */
export const getUploadFileUrl = () => {
  return `/api/files/upload`;
};

export const uploadFile = async (
  uploadFileBody: UploadFileBody,
  options?: RequestInit,
): Promise<FileRecord> => {
  const formData = new FormData();
  formData.append(`file`, uploadFileBody.file);
  if (uploadFileBody.lectureId !== undefined) {
    formData.append(`lectureId`, uploadFileBody.lectureId.toString());
  }
  if (uploadFileBody.courseId !== undefined) {
    formData.append(`courseId`, uploadFileBody.courseId.toString());
  }
  formData.append(`title`, uploadFileBody.title);
  formData.append(`type`, uploadFileBody.type);

  return customFetch<FileRecord>(getUploadFileUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

